HOST, PW = "192.168.2.203", "hCJM3BaKYsbaSOw-F%FjQJ@Z"
TS = time.strftime("%Y%m%d_%H%M%S")

c = paramiko.SSHClient()
c.set_missing_host_key_policy(paramiko.AutoAddPolicy())
c.connect(HOST, username="root", password=PW, timeout=25, allow_agent=False, look_for_keys=False)
sftp = c.open_sftp()


def run(cmd, timeout=60):
    _, o, e = c.exec_command(cmd, timeout=timeout)
    out = o.read().decode(errors="replace")
    err = e.read().decode(errors="replace")
    return out, err


def write(path, content):
    with sftp.open(path, "w") as f:
        f.write(content)


def backup(path):
    run(f"cp -a '{path}' '{path}.bak_instant_{TS}'")


# ---------- 1) clone_instant.php (page cache + softnav inject flag) ----------
CLONE_INSTANT = r'''<?php
/**
 * CLONE ONLY — instant navigation helpers.
 * Page HTML cache + early session release + soft-nav asset flag.
 */
if (!defined('B_PROLOG_INCLUDED') && !defined('CLONE_INSTANT_BOOT')) {
    // allow include from init
}

function CloneInstant_IsClone()
{
    static $v = null;
    if ($v === null) {
        $v = (gethostname() === 'crm-clone');
    }
    return $v;
}

function CloneInstant_ShouldCachePage()
{
    if (!CloneInstant_IsClone()) {
        return false;
    }
    if (($_SERVER['REQUEST_METHOD'] ?? 'GET') !== 'GET') {
        return false;
    }
    if (!empty($_POST)) {
        return false;
    }
    if (!empty($_REQUEST['SHOW_PAGE_AJAX']) || !empty($_REQUEST['CLONE_TAB_FRAG'])) {
        return false;
    }
    if (!empty($_REQUEST['login']) || !empty($_REQUEST['logout']) || !empty($_REQUEST['USER_LOGIN'])) {
        return false;
    }
    $uri = $_SERVER['REQUEST_URI'] ?? '';
    if ($uri === '' || strpos($uri, '/bitrix/') === 0) {
        return false;
    }
    // skip obvious mutating/query tools
    if (preg_match('/(ajax|action|save|delete|edit|ADD_NEW|convert_format)=/i', $uri)) {
        return false;
    }
    global $USER;
    if (!is_object($USER) || !$USER->IsAuthorized()) {
        return false;
    }
    return true;
}

function CloneInstant_CacheKey()
{
    global $USER;
    $uri = $_SERVER['REQUEST_URI'] ?? '/';
    $uid = is_object($USER) ? (int)$USER->GetID() : 0;
    return 'html_' . md5($uri . '|' . $uid);
}

function CloneInstant_OnBeforeProlog()
{
    if (!CloneInstant_ShouldCachePage()) {
        return;
    }
    // Release session lock ASAP so parallel tab/menu clicks do not queue.
    if (function_exists('session_status') && session_status() === PHP_SESSION_ACTIVE) {
        @session_write_close();
    }
    $cache = \Bitrix\Main\Data\Cache::createInstance();
    $id = CloneInstant_CacheKey();
    if ($cache->initCache(180, $id, '/clone_instant_page')) {
        $html = $cache->getVars();
        if (is_string($html) && strlen($html) > 500) {
            global $APPLICATION;
            if (is_object($APPLICATION)) {
                $APPLICATION->RestartBuffer();
            }
            header('X-Clone-Instant-Cache: HIT');
            echo $html;
            die();
        }
    }
    $GLOBALS['CLONE_INSTANT_CACHE_MISS'] = true;
    $GLOBALS['CLONE_INSTANT_CACHE_ID'] = $id;
}

function CloneInstant_OnEndBufferContent(&$content)
{
    if (empty($GLOBALS['CLONE_INSTANT_CACHE_MISS'])) {
        return;
    }
    if (!CloneInstant_ShouldCachePage()) {
        return;
    }
    if (!is_string($content) || strlen($content) < 800) {
        return;
    }
    // do not cache login / errors
    if (strpos($content, 'name="USER_LOGIN"') !== false && strpos($content, 'left_menu') === false) {
        return;
    }
    if (strpos($content, 'Ошибка вкладки') !== false || strpos($content, 'Fatal error') !== false) {
        return;
    }
    $cache = \Bitrix\Main\Data\Cache::createInstance();
    $id = $GLOBALS['CLONE_INSTANT_CACHE_ID'] ?? CloneInstant_CacheKey();
    if ($cache->startDataCache(180, $id, '/clone_instant_page')) {
        $cache->endDataCache($content);
    }
    header('X-Clone-Instant-Cache: STORE');
}

function CloneInstant_Register()
{
    if (!CloneInstant_IsClone()) {
        return;
    }
    AddEventHandler('main', 'OnBeforeProlog', 'CloneInstant_OnBeforeProlog');
    AddEventHandler('main', 'OnEndBufferContent', 'CloneInstant_OnEndBufferContent');
}

CloneInstant_Register();
'''

write("/var/www/html/bitrix/php_interface/include/clone_instant.php", CLONE_INSTANT)
print("wrote clone_instant.php")

