      else history.replaceState('', '', window.location.pathname);
    } catch (e) {}
    return pane;
  }

  function inject(pane, html) {
    if (!pane) return;
    pane.innerHTML = html;
    pane.setAttribute('data-loaded', '1');
    // re-run inline scripts inside tab
    pane.querySelectorAll('script').forEach(function (old) {
      var s = document.createElement('script');
      if (old.src) s.src = old.src;
      else s.textContent = old.textContent;
      old.parentNode.replaceChild(s, old);
    });
  }

  function fetchTab(tab_num) {
    var key = tabKey(tab_num);
    if (window.__cloneTabHtml[key]) {
      return Promise.resolve(window.__cloneTabHtml[key]);
    }
    if (window.__cloneTabLoading[key]) return window.__cloneTabLoading[key];
    var url = window.location.pathname + (key ? ('?tab=' + encodeURIComponent(key)) : '') +
      (key ? '&' : '?') + 'CLONE_TAB_FRAG=Y&SHOW_PAGE_AJAX=Y';
    // fix ?& 
    url = window.location.pathname + '?CLONE_TAB_FRAG=Y&SHOW_PAGE_AJAX=Y' + (key ? ('&tab=' + encodeURIComponent(key)) : '');
    var p = fetch(url, { credentials: 'same-origin', headers: { 'X-Requested-With': 'XMLHttpRequest' } })
      .then(function (r) { return r.text(); })
      .then(function (html) {
        window.__cloneTabHtml[key] = html;
        delete window.__cloneTabLoading[key];
        return html;
      })
      .catch(function (err) {
        delete window.__cloneTabLoading[key];
        throw err;
      });
    window.__cloneTabLoading[key] = p;
    return p;
  }

  window.change_tabs = function (elem, tab_num) {
    if (window.__clone_tab_busy) return;
    var key = tabKey(tab_num);
    var pane = setActiveUI(tab_num);
    if (!pane) return;

    if (pane.getAttribute('data-loaded') === '1' && pane.innerHTML.trim() !== '') {
      window.__cloneTabHtml[key] = pane.innerHTML;
      return;
    }
    if (window.__cloneTabHtml[key]) {
      inject(pane, window.__cloneTabHtml[key]);
      return;
    }

    window.__clone_tab_busy = true;
    pane.innerHTML = '<div style="padding:20px;opacity:.7">Загрузка…</div>';
    fetchTab(tab_num).then(function (html) {
      inject(pane, html);
    }).catch(function () {
      // fallback full navigation
      window.location.href = window.location.pathname + (key ? ('?tab=' + encodeURIComponent(key)) : '');
    }).then(function () {
      window.__clone_tab_busy = false;
    });
  };

  function prefetchAll() {
    var root = document.querySelector('[role="tabs"]');
    if (!root) return;
    var tabs = [];
    root.querySelectorAll('.change_view[data-tab]').forEach(function (el) {
      tabs.push(el.getAttribute('data-tab') || '');
    });
    var i = 0;
    function next() {
      if (i >= tabs.length) return;
      var t = tabs[i++];
      var pane = root.querySelector('.one_tab[tab="' + t + '"]');
      if (pane && pane.getAttribute('data-loaded') === '1') {
        window.__cloneTabHtml[t] = pane.innerHTML;
        setTimeout(next, 30);
        return;
