      fetchTab(t).then(function (html) {
        if (pane && pane.getAttribute('data-loaded') !== '1') {
          // keep hidden panes filled so switch is instant
          inject(pane, html);
          pane.classList.remove('active');
        }
      }).catch(function(){}).then(function () { setTimeout(next, 80); });
    }
    next();
  }

  if (document.readyState === 'complete') setTimeout(prefetchAll, 200);
  else window.addEventListener('load', function () { setTimeout(prefetchAll, 200); });
})();
