SOFT_NAV = r'''/**
 * CLONE ONLY — soft navigation for left menu + hover prefetch.
 * Makes section switches feel instant using memory cache of HTML documents.
 */
(function () {
  if (window.__cloneSoftNav) return;
  window.__cloneSoftNav = true;
  if (location.hostname !== '192.168.2.203' && location.hostname !== 'crm-clone' && location.hostname.indexOf('203') === -1) {
    // still allow when opened by IP
  }

  var cache = window.__clonePageCache = window.__clonePageCache || {};
  var PREFETCH_PATHS = [
    '/dashboard/', '/lenta/', '/job/', '/project/', '/client/', '/client_f/',
    '/deal/', '/quest/', '/quest_new/', '/cash/', '/equ/', '/root/doc/',
    '/education/', '/wiki/', '/po/', '/type_po/'
  ];

  function sameOrigin(href) {
    try {
      var u = new URL(href, location.origin);
      return u.origin === location.origin;
    } catch (e) { return false; }
  }

  function normalize(href) {
    try {
      var u = new URL(href, location.origin);
      return u.pathname + (u.search || '');
    } catch (e) { return href; }
  }

  function isNavCandidate(a) {
    if (!a || !a.getAttribute) return false;
    var href = a.getAttribute('href');
    if (!href || href === '#' || href.indexOf('javascript:') === 0) return false;
    if (a.target && a.target !== '' && a.target !== '_self') return false;
    if (!sameOrigin(href)) return false;
    var path = normalize(href);
    if (path.indexOf('/bitrix/') === 0) return false;
    if (path.indexOf('/client/detail/') === 0) return false; // detail has own tab logic
    return true;
  }

  function extractMain(doc) {
    // Prefer main work area; fall back to body children swap markers used by template
    return doc.querySelector('.workarea') ||
      doc.querySelector('#workarea') ||
      doc.querySelector('.page_content') ||
      doc.querySelector('.content') ||
      doc.querySelector('main') ||
      doc.body;
  }

  function currentMain() {
    return document.querySelector('.workarea') ||
      document.querySelector('#workarea') ||
      document.querySelector('.page_content') ||
      document.querySelector('.content') ||
      document.querySelector('main');
  }

  function fetchPage(path) {
    if (cache[path] && cache[path].html) return Promise.resolve(cache[path]);
    return fetch(path, { credentials: 'same-origin', headers: { 'X-Clone-SoftNav': '1' } })
      .then(function (r) { return r.text().then(function (t) { return { ok: r.ok, status: r.status, html: t }; }); })
      .then(function (res) {
        if (res.ok && res.html && res.html.indexOf('name="USER_LOGIN"') === -1) {
          cache[path] = res;
        }
        return res;
      });
  }

  function softGoto(path, push) {
    var main = currentMain();
    if (!main) {
      location.href = path;
      return;
    }
    var apply = function (res) {
      if (!res || !res.html) { location.href = path; return; }
      var parser = new DOMParser();
      var doc = parser.parseFromString(res.html, 'text/html');
      var next = extractMain(doc);
      if (!next) { location.href = path; return; }
      main.innerHTML = next.innerHTML;
      document.title = doc.title || document.title;
      // run scripts from new main
      main.querySelectorAll('script').forEach(function (old) {
        var s = document.createElement('script');
        if (old.src) s.src = old.src; else s.textContent = old.textContent;
        old.parentNode.replaceChild(s, old);
      });
      if (push) history.pushState({ soft: 1 }, '', path);
      // mark active menu
      document.querySelectorAll('a[href]').forEach(function (a) {
        if (!isNavCandidate(a)) return;
        var p = normalize(a.getAttribute('href'));
        a.classList.toggle('active', p === path || (path.indexOf(p) === 0 && p.length > 1));
      });
      window.scrollTo(0, 0);
    };

    if (cache[path] && cache[path].html) {
      apply(cache[path]);
      // refresh in background
      fetchPage(path).catch(function(){});
      return;
    }
    main.style.opacity = '0.5';
    fetchPage(path).then(function (res) {
      main.style.opacity = '';
      apply(res);
    }).catch(function () {
      location.href = path;
    });
  }

  document.addEventListener('click', function (ev) {
    var a = ev.target && ev.target.closest ? ev.target.closest('a') : null;
    if (!isNavCandidate(a)) return;
    // only left menu / primary nav areas
    var inMenu = a.closest('.left_menu, .left-menu, #left_menu, .sidebar, .menu_left, nav, .main_menu');
    if (!inMenu) return;
    var path = normalize(a.getAttribute('href'));
    if (path === normalize(location.pathname + location.search)) {
      ev.preventDefault();
      return;
    }
    ev.preventDefault();
    softGoto(path, true);
  }, true);

  document.addEventListener('mouseover', function (ev) {
    var a = ev.target && ev.target.closest ? ev.target.closest('a') : null;
    if (!isNavCandidate(a)) return;
    var path = normalize(a.getAttribute('href'));
    if (!cache[path]) fetchPage(path).catch(function(){});
  }, true);

  window.addEventListener('popstate', function () {
    softGoto(normalize(location.pathname + location.search), false);
  });

  // warm popular sections after idle
  function warm() {
    var i = 0;
    function next() {
      if (i >= PREFETCH_PATHS.length) return;
      var p = PREFETCH_PATHS[i++];
      if (cache[p]) { setTimeout(next, 20); return; }
      fetchPage(p).catch(function(){}).then(function () { setTimeout(next, 120); });
    }
    next();
  }
  if (document.readyState === 'complete') setTimeout(warm, 400);
  else window.addEventListener('load', function () { setTimeout(warm, 400); });
})();
'''

