function CloneInstant_Log($msg)
{
    @file_put_contents('/tmp/clone_instant.log', date('H:i:s') . ' ' . $msg . "\n", FILE_APPEND);
}

function CloneInstant_ShouldCachePage()
{
    if (!CloneInstant_IsClone()) {
        return false;
    }
    if (PHP_SAPI === 'cli') {
        return false;
    }
    if (($_SERVER['REQUEST_METHOD'] ?? 'GET') !== 'GET') {
        return false;
    }
    if (!empty($_POST)) {
        return false;
    }
    if (!empty($_REQUEST['SHOW_PAGE_AJAX']) || !empty($_REQUEST['CLONE_TAB_FRAG'])) {
        return false;
    }
    if (!empty($_REQUEST['login']) || !empty($_REQUEST['logout']) || !empty($_REQUEST['USER_LOGIN'])) {
