        return false;
    }
    if (preg_match('/[?&](action|save|delete|ADD_NEW|convert_format)=/i', $uri)) {
        return false;
    }
    global $USER;
    if (!is_object($USER) || !$USER->IsAuthorized()) {
        return false;
    }
    return true;
}

function CloneInstant_CacheKey()
{
    global $USER;
    $uri = $_SERVER['REQUEST_URI'] ?? '/';
    $uid = is_object($USER) ? (int)$USER->GetID() : 0;
    return 'html_' . md5($uri . '|' . $uid);
}

function CloneInstant_OnBeforeProlog()
{
    if (!CloneInstant_IsClone()) {
        return;
    }
    // Always try to release session lock early on GET
    if ((($_SERVER['REQUEST_METHOD'] ?? 'GET') === 'GET') && empty($_POST)
        && function_exists('session_status') && session_status() === PHP_SESSION_ACTIVE) {
        @session_write_close();
    }
    if (!CloneInstant_ShouldCachePage()) {
