    $cache = \Bitrix\Main\Data\Cache::createInstance();
    $id = CloneInstant_CacheKey();
    if ($cache->initCache(180, $id, '/clone_instant_page')) {
        $html = $cache->getVars();
        if (is_string($html) && strlen($html) > 500) {
            global $APPLICATION;
            if (is_object($APPLICATION)) {
                $APPLICATION->RestartBuffer();
            }
            if (!headers_sent()) {
                header('X-Clone-Instant-Cache: HIT');
            }
            CloneInstant_Log('HIT ' . ($_SERVER['REQUEST_URI'] ?? ''));
            echo $html;
            die();
        }
    }
    $GLOBALS['CLONE_INSTANT_CACHE_MISS'] = true;
    $GLOBALS['CLONE_INSTANT_CACHE_ID'] = $id;
    CloneInstant_Log('MISS ' . ($_SERVER['REQUEST_URI'] ?? ''));
}

function CloneInstant_OnEndBufferContent(&$content)
{
    if (empty($GLOBALS['CLONE_INSTANT_CACHE_MISS'])) {
        return;
    }
    if (!CloneInstant_ShouldCachePage()) {
        return;
    }
    if (!is_string($content) || strlen($content) < 800) {
        return;
    }
    if (strpos($content, 'name="USER_LOGIN"') !== false && strpos($content, 'left_menu') === false) {
        return;
    }
    if (strpos($content, 'Fatal error') !== false) {
        return;
    }
    $cache = \Bitrix\Main\Data\Cache::createInstance();
    $id = $GLOBALS['CLONE_INSTANT_CACHE_ID'] ?? CloneInstant_CacheKey();
    if ($cache->startDataCache(180, $id, '/clone_instant_page')) {
        $cache->endDataCache($content);
        CloneInstant_Log('STORE ' . ($_SERVER['REQUEST_URI'] ?? '') . ' len=' . strlen($content));
    }
}

if (CloneInstant_IsClone()) {
    AddEventHandler('main', 'OnBeforeProlog', 'CloneInstant_OnBeforeProlog');
    AddEventHandler('main', 'OnEndBufferContent', 'CloneInstant_OnEndBufferContent');
}
'''

