<script>
/* CLONE: fast tab switch via fragment AJAX (no full soft-nav of site) */
(function () {
  if (window.__cloneTabsV2) return;
  window.__cloneTabsV2 = true;
  window.__cloneTabHtml = window.__cloneTabHtml || {};
  window.__cloneTabLoading = window.__cloneTabLoading || {};

  function key(tab) { return tab || ''; }

  function setActive(tab_num) {
    var root = document.querySelector('[role="tabs"]') || document;
    root.querySelectorAll('.change_view').forEach(function (el) { el.classList.remove('active'); });
    root.querySelectorAll('.one_tab').forEach(function (el) { el.classList.remove('active'); });
    var k = key(tab_num);
    root.querySelectorAll('.change_view[data-tab]').forEach(function (el) {
      if ((el.getAttribute('data-tab') || '') === k) el.classList.add('active');
    });
    var pane = root.querySelector('.one_tab[tab="' + k + '"]');
    if (pane) pane.classList.add('active');
    try {
      if (k) history.replaceState('', '', location.pathname + '?tab=' + encodeURIComponent(k));
      else history.replaceState('', '', location.pathname);
    } catch (e) {}
    return pane;
  }

  function runScripts(pane) {
    pane.querySelectorAll('script').forEach(function (old) {
      var s = document.createElement('script');
      if (old.src) s.src = old.src;
      else s.textContent = old.textContent;
      old.parentNode.replaceChild(s, old);
    });
  }

  function inject(pane, html) {
    pane.innerHTML = html;
    pane.setAttribute('data-loaded', '1');
    runScripts(pane);
  }

  function fetchTab(tab_num) {
    var k = key(tab_num);
    if (window.__cloneTabHtml[k]) return Promise.resolve(window.__cloneTabHtml[k]);
    if (window.__cloneTabLoading[k]) return window.__cloneTabLoading[k];
    var url = location.pathname + '?CLONE_TAB_FRAG=Y&SHOW_PAGE_AJAX=Y' + (k ? ('&tab=' + encodeURIComponent(k)) : '');
    var p = fetch(url, { credentials: 'same-origin', headers: { 'X-Requested-With': 'XMLHttpRequest' } })
      .then(function (r) { return r.text(); })
      .then(function (html) {
        if (!html || html.indexOf('name="USER_LOGIN"') !== -1) throw new Error('auth');
        if (html.indexOf('Ошибка вкладки') !== -1 || html.indexOf('Parse error') !== -1) throw new Error('tab');
        window.__cloneTabHtml[k] = html;
        delete window.__cloneTabLoading[k];
        return html;
      })
      .catch(function (err) {
        delete window.__cloneTabLoading[k];
        throw err;
      });
    window.__cloneTabLoading[k] = p;
    return p;
  }

  window.__cloneChangeTabs = function (elem, tab_num) {
    if (window.__clone_tab_busy) return;
    var k = key(tab_num);
    var pane = setActive(tab_num);
    if (!pane) return;
    if (pane.getAttribute('data-loaded') === '1' && pane.innerHTML.trim()) {
      window.__cloneTabHtml[k] = pane.innerHTML;
      return;
    }
    if (window.__cloneTabHtml[k]) {
      inject(pane, window.__cloneTabHtml[k]);
      return;
    }
    window.__clone_tab_busy = true;
    pane.innerHTML = '<div style="padding:18px;opacity:.65">Загрузка…</div>';
    fetchTab(tab_num).then(function (html) {
      inject(pane, html);
    }).catch(function () {
      location.href = location.pathname + (k ? ('?tab=' + encodeURIComponent(k)) : '');
    }).then(function () {
      window.__clone_tab_busy = false;
    });
  };
  window.change_tabs = window.__cloneChangeTabs;

  function prefetchAll() {
    var root = document.querySelector('[role="tabs"]');
    if (!root) return;
    var list = [];
    root.querySelectorAll('.change_view[data-tab]').forEach(function (el) {
      list.push(el.getAttribute('data-tab') || '');
    });
    var i = 0;
    function next() {
      if (i >= list.length) return;
      var t = list[i++];
      var pane = root.querySelector('.one_tab[tab="' + t + '"]');
      if (pane && pane.getAttribute('data-loaded') === '1' && pane.innerHTML.trim()) {
        window.__cloneTabHtml[t] = pane.innerHTML;
        setTimeout(next, 20);
        return;
      }
      fetchTab(t).then(function (html) {
        if (pane && pane.getAttribute('data-loaded') !== '1') {
          inject(pane, html);
          pane.classList.remove('active');
        }
      }).catch(function () {}).then(function () { setTimeout(next, 60); });
    }
    next();
  }
  if (document.readyState === 'complete') setTimeout(prefetchAll, 250);
  else window.addEventListener('load', function () { setTimeout(prefetchAll, 250); });
})();
</script>

