<script>
/* CLONE_TABS_FAST: AJAX switch via SHOW_PAGE_AJAX, extract .one_tab.active only (no CLONE_TAB_FRAG) */
(function () {
  if (window.__cloneTabsFast) return;
  window.__cloneTabsFast = true;
  window.__cloneTabHtml = window.__cloneTabHtml || {};
  window.__cloneTabLoading = window.__cloneTabLoading || {};

  function key(tab) { return tab || ''; }

  function hidePreload() {
    try { document.querySelectorAll('#preload').forEach(function (n) { n.remove(); }); } catch (e) {}
    try { if (window.jQuery) { jQuery('#preload').remove(); jQuery('body').hide_preload(); } } catch (e) {}
  }

  function setActive(tab_num) {
    var root = document.querySelector('[role="tabs"]') || document;
    root.querySelectorAll('.change_current_data .change_view').forEach(function (el) {
      el.classList.remove('active');
    });
    root.querySelectorAll('.one_tab').forEach(function (el) { el.classList.remove('active'); });
    var k = key(tab_num);
    var btn = root.querySelector('.change_current_data .change_view[data-tab="' + k + '"]');
    if (btn) btn.classList.add('active');
    var pane = root.querySelector('.one_tab[tab="' + k + '"]');
    if (pane) pane.classList.add('active');
    try {
      if (k) history.replaceState('', '', location.pathname + '?tab=' + encodeURIComponent(k));
      else history.replaceState('', '', location.pathname);
    } catch (e) {}
    return pane;
  }

  function extractPaneHtml(html, tab_num) {
    var doc = document.implementation.createHTMLDocument('');
    doc.documentElement.innerHTML = html;
    var k = key(tab_num);
    var pane = doc.querySelector('.one_tab.active') || doc.querySelector('.one_tab[tab="' + k + '"]');
    if (!pane) return null;
    // Guard: never inject nested card chrome
    var bad = pane.querySelector('.change_current_data, .lid_detail, [role="tabs"]');
    if (bad && bad !== pane) {
      // if nested chrome slipped in, keep only deepest active tab body if possible
      var inner = pane.querySelector('.one_tab.active') || pane;
      return inner.innerHTML;
    }
    return pane.innerHTML;
  }

  function runScripts(pane) {
    pane.querySelectorAll('script').forEach(function (old) {
      var txt = old.textContent || '';
      // skip bootstraps that rebind tabs / full page
      if (/change_tabs|__cloneTabs|CLONE_TABS|lid_detail|location\.href\s*=/.test(txt) && !old.src) {
        old.parentNode.removeChild(old);
        return;
      }
      var s = document.createElement('script');
      if (old.src) s.src = old.src;
      else s.textContent = txt;
      old.parentNode.replaceChild(s, old);
    });
  }

  function inject(pane, html) {
    pane.innerHTML = html;
    pane.setAttribute('data-loaded', '1');
    runScripts(pane);
    hidePreload();
  }

  function fetchTab(tab_num) {
    var k = key(tab_num);
    if (window.__cloneTabHtml[k]) return Promise.resolve(window.__cloneTabHtml[k]);
    if (window.__cloneTabLoading[k]) return window.__cloneTabLoading[k];
    var url = location.pathname + '?SHOW_PAGE_AJAX=Y' + (k ? ('&tab=' + encodeURIComponent(k)) : '');
    var p = fetch(url, { credentials: 'same-origin', headers: { 'X-Requested-With': 'XMLHttpRequest' } })
      .then(function (r) { return r.text(); })
      .then(function (html) {
        if (!html || html.indexOf('name="USER_LOGIN"') !== -1) throw new Error('auth');
        if (html.indexOf('Parse error') !== -1 || html.indexOf('Fatal error') !== -1) throw new Error('php');
        var extracted = extractPaneHtml(html, k);
        if (!extracted || !extracted.trim()) throw new Error('empty');
        // deal guard: broken frag started with ")"
        if (extracted.replace(/^\s+/, '').charAt(0) === ')') throw new Error('broken');
        window.__cloneTabHtml[k] = extracted;
        delete window.__cloneTabLoading[k];
        return extracted;
      })
      .catch(function (err) {
        delete window.__cloneTabLoading[k];
        throw err;
      });
    window.__cloneTabLoading[k] = p;
    return p;
  }

  window.change_tabs = function (elem, tab_num) {
    hidePreload();
    if (window.__clone_tab_busy) return;
    var k = key(tab_num);
    var pane = setActive(tab_num);
    if (!pane) {
      location.href = location.pathname + (k ? ('?tab=' + encodeURIComponent(k)) : '');
      return;
    }
    if (pane.getAttribute('data-loaded') === '1' && pane.innerHTML.trim()) {
      window.__cloneTabHtml[k] = pane.innerHTML;
      return;
    }
    if (window.__cloneTabHtml[k]) {
      inject(pane, window.__cloneTabHtml[k]);
      return;
    }
    window.__clone_tab_busy = true;
    pane.innerHTML = '<div style="padding:18px;opacity:.65">Загрузка…</div>';
    fetchTab(tab_num).then(function (html) {
      inject(pane, html);
    }).catch(function () {
      location.href = location.pathname + (k ? ('?tab=' + encodeURIComponent(k)) : '');
    }).then(function () {
      window.__clone_tab_busy = false;
      hidePreload();
    });
  };
  window.__cloneChangeTabs = window.change_tabs;

  function prefetchAll() {
    var root = document.querySelector('[role="tabs"]');
    if (!root) return;
    var list = [];
    root.querySelectorAll('.change_current_data .change_view[data-tab]').forEach(function (el) {
      list.push(el.getAttribute('data-tab') || '');
    });
    var i = 0;
    function next() {
      if (i >= list.length) return;
      var t = list[i++];
      if (window.__cloneTabHtml[t]) { setTimeout(next, 30); return; }
      var pane = root.querySelector('.one_tab[tab="' + t + '"]');
      if (pane && pane.getAttribute('data-loaded') === '1' && pane.innerHTML.trim()) {
        window.__cloneTabHtml[t] = pane.innerHTML;
        setTimeout(next, 30);
        return;
      }
      fetchTab(t).then(function () {}).catch(function () {}).then(function () {
        setTimeout(next, 80);
      });
    }
    next();
  }
  if (document.readyState === 'complete') setTimeout(prefetchAll, 400);
  else window.addEventListener('load', function () { setTimeout(prefetchAll, 400); });
})();
</script>

