/* CLONE_TABS_AJAX — safe tab switch for all detail cards on crm-clone
 * - If pane already has content: instant local toggle (no request)
 * - If pane empty (lazy tabs): SHOW_PAGE_AJAX fetch, extract .one_tab.active only
 * - Never inject nested card chrome; fall back to full navigation on errors
 */
(function () {
  if (window.__cloneTabsAjaxGlobal) return;
  window.__cloneTabsAjaxGlobal = true;
  window.__cloneTabHtml = window.__cloneTabHtml || {};
  window.__cloneTabLoading = window.__cloneTabLoading || {};

  function key(tab) { return tab || ''; }

  function hidePreload() {
    try { document.querySelectorAll('#preload').forEach(function (n) { n.remove(); }); } catch (e) {}
    try {
      if (window.jQuery) {
        jQuery('#preload').remove();
        if (jQuery.fn.hide_preload) jQuery('body').hide_preload();
      }
    } catch (e) {}
  }

  function rootFrom(elem) {
    if (elem && elem.closest) {
      var r = elem.closest('[role="tabs"]');
      if (r) return r;
    }
    return document.querySelector('[role="tabs"]') || document;
  }

  function cacheKey(tab) {
    return location.pathname + '::' + key(tab);
  }

  function setActive(root, tab_num) {
    var k = key(tab_num);
    root.querySelectorAll('.change_current_data .change_view, .change_current_data.tabs_over .change_view, .tabs_over > .change_view').forEach(function (el) {
      el.classList.remove('active');
    });
    // also classic spans without data-tab: match by onclick/tab order via data-tab or index
    var btns = root.querySelectorAll('.change_current_data .change_view, .change_current_data.tabs_over .change_view');
    if (!btns.length) btns = root.querySelectorAll('.change_view');
    btns.forEach(function (el) {
      var dt = el.getAttribute('data-tab');
      if (dt !== null) {
        if (dt === k) el.classList.add('active');
      }
    });
    // fallback: if no data-tab matched, try click target
    var any = root.querySelector('.change_view.active');
    if (!any && window.__cloneLastTabBtn) {
      try { window.__cloneLastTabBtn.classList.add('active'); } catch (e) {}
    }

    root.querySelectorAll('.one_tab').forEach(function (el) { el.classList.remove('active'); });
    var pane = root.querySelector('.one_tab[tab="' + k + '"]');
    if (pane) pane.classList.add('active');

    try {
      if (k) history.replaceState('', '', location.pathname + '?tab=' + encodeURIComponent(k));
      else history.replaceState('', '', location.pathname);
    } catch (e) {}
    return pane;
  }

  function looksLikeChrome(html) {
    if (!html) return true;
    var s = html.replace(/^\s+/, '');
    if (s.charAt(0) === ')') return true;
    if (/class="[^"]*lid_detail/.test(s.slice(0, 500))) return true;
    if (/class="[^"]*change_current_data/.test(s.slice(0, 800)) && /class="[^"]*one_tab/.test(html)) return true;
    return false;
  }

  function extractPaneHtml(html, tab_num) {
    var doc = document.implementation.createHTMLDocument('');
    doc.documentElement.innerHTML = html;
    var k = key(tab_num);
    var pane = doc.querySelector('.one_tab.active') || doc.querySelector('.one_tab[tab="' + k + '"]');
    if (!pane) return null;
    var nested = pane.querySelector('.lid_detail, .change_current_data, [role="tabs"] .change_current_data');
    if (nested) {
      var inner = pane.querySelector('.one_tab.active') || pane.querySelector('.one_tab[tab="' + k + '"]');
      if (inner && inner !== pane) return inner.innerHTML;
    }
    return pane.innerHTML;
  }

  function runScripts(pane) {
    pane.querySelectorAll('script').forEach(function (old) {
      var txt = old.textContent || '';
      if (!old.src && /change_tabs|__cloneTabs|CLONE_TABS|lid_detail|location\.href\s*=/.test(txt)) {
        old.parentNode.removeChild(old);
        return;
      }
      var s = document.createElement('script');
      if (old.src) s.src = old.src;
      else s.textContent = txt;
      old.parentNode.replaceChild(s, old);
    });
  }

  function inject(pane, html) {
    pane.innerHTML = html;
    pane.setAttribute('data-loaded', '1');
    runScripts(pane);
    hidePreload();
  }

  function paneHasContent(pane) {
    if (!pane) return false;
    if (pane.getAttribute('data-loaded') === '1' && pane.innerHTML.trim()) return true;
    var t = (pane.innerHTML || '').replace(/\s+/g, ' ').trim();
    if (t.length < 40) return false;
    if (/Загрузка…|clone-tab-loading/.test(t) && t.length < 120) return false;
    return true;
  }

  function fetchTab(tab_num) {
    var ck = cacheKey(tab_num);
    if (window.__cloneTabHtml[ck]) return Promise.resolve(window.__cloneTabHtml[ck]);
    if (window.__cloneTabLoading[ck]) return window.__cloneTabLoading[ck];
    var k = key(tab_num);
    var url = location.pathname + '?SHOW_PAGE_AJAX=Y' + (k ? ('&tab=' + encodeURIComponent(k)) : '');
    var p = fetch(url, { credentials: 'same-origin', headers: { 'X-Requested-With': 'XMLHttpRequest' } })
      .then(function (r) { return r.text(); })
      .then(function (html) {
        if (!html || html.indexOf('name="USER_LOGIN"') !== -1) throw new Error('auth');
        if (html.indexOf('Parse error') !== -1 || html.indexOf('Fatal error') !== -1) throw new Error('php');
        var extracted = extractPaneHtml(html, k);
        if (!extracted || !extracted.trim()) throw new Error('empty');
        if (looksLikeChrome(extracted)) throw new Error('chrome');
        window.__cloneTabHtml[ck] = extracted;
        delete window.__cloneTabLoading[ck];
        return extracted;
      })
      .catch(function (err) {
        delete window.__cloneTabLoading[ck];
        throw err;
      });
    window.__cloneTabLoading[ck] = p;
    return p;
  }

  function changeTabs(elem, tab_num) {
    hidePreload();
    if (window.__clone_tab_busy) return;
    window.__cloneLastTabBtn = elem || null;
    if (elem && elem.classList) elem.classList.add('active');

    var root = rootFrom(elem);
    var k = key(tab_num);
    var pane = setActive(root, tab_num);
    if (!pane) {
      location.href = location.pathname + (k ? ('?tab=' + encodeURIComponent(k)) : '');
      return;
    }

    // ensure clicked button active even without data-tab
    if (elem && elem.classList && elem.classList.contains('change_view')) {
      root.querySelectorAll('.change_current_data .change_view').forEach(function (el) {
        el.classList.remove('active');
      });
      elem.classList.add('active');
    }

    var ck = cacheKey(k);
    if (paneHasContent(pane)) {
      window.__cloneTabHtml[ck] = pane.innerHTML;
      pane.setAttribute('data-loaded', '1');
      return;
    }
    if (window.__cloneTabHtml[ck]) {
      inject(pane, window.__cloneTabHtml[ck]);
      return;
    }

    window.__clone_tab_busy = true;
    pane.innerHTML = '<div class="clone-tab-loading" style="padding:18px;opacity:.65">Загрузка…</div>';
    fetchTab(k).then(function (html) {
      inject(pane, html);
    }).catch(function () {
      location.href = location.pathname + (k ? ('?tab=' + encodeURIComponent(k)) : '');
    }).then(function () {
      window.__clone_tab_busy = false;
      hidePreload();
    });
  }

  window.change_tabs = changeTabs;
  window.__cloneChangeTabs = changeTabs;

  function enhanceDataTabs(root) {
    root = root || document;
    root.querySelectorAll('.change_current_data .change_view[onclick], .change_current_data.tabs_over .change_view[onclick]').forEach(function (el) {
      if (el.hasAttribute('data-tab')) return;
      var oc = el.getAttribute('onclick') || '';
      var m = oc.match(/change_tabs\s*\(\s*this\s*,\s*'([^']*)'\s*\)/);
      if (m) el.setAttribute('data-tab', m[1]);
    });
    root.querySelectorAll('.one_tab').forEach(function (pane) {
      if (pane.classList.contains('active') && paneHasContent(pane)) {
        pane.setAttribute('data-loaded', '1');
        window.__cloneTabHtml[cacheKey(pane.getAttribute('tab') || '')] = pane.innerHTML;
      }
    });
  }

  function prefetchAll() {
    var root = document.querySelector('[role="tabs"]');
    if (!root) return;
    enhanceDataTabs(root);
    var list = [];
    root.querySelectorAll('.change_current_data .change_view[data-tab], .change_current_data.tabs_over .change_view[data-tab]').forEach(function (el) {
      list.push(el.getAttribute('data-tab') || '');
    });
    var i = 0, workers = 0, maxWorkers = 2;
    function pump() {
      while (workers < maxWorkers && i < list.length) {
        var t = list[i++];
        var ck = cacheKey(t);
        if (window.__cloneTabHtml[ck]) continue;
        var pane = root.querySelector('.one_tab[tab="' + t + '"]');
        if (paneHasContent(pane)) {
          window.__cloneTabHtml[ck] = pane.innerHTML;
          continue;
        }
        workers++;
        fetchTab(t).catch(function () {}).then(function () {
          workers--;
          pump();
        });
      }
    }
    pump();
  }

  function boot() {
    enhanceDataTabs(document);
    setTimeout(prefetchAll, 150);
  }
  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', boot);
  else boot();
  window.addEventListener('load', function () { setTimeout(prefetchAll, 300); });
})();

