# -*- coding: utf-8 -*-
from pathlib import Path
import re
import subprocess

TPL = Path("/var/www/html/bitrix/templates/vsevset_template")

# bump header cache buster
h = TPL / "header.php"
ht = h.read_text(encoding="utf-8", errors="replace")
ht = ht.replace("clone_tabs_ajax.js?v=20260722a", "clone_tabs_ajax.js?v=20260722b")
h.write_text(ht, encoding="utf-8")
print("header version bumped")

# Patch all component script.js change_tabs to delegate to global
delegate = """function change_tabs(elem, tab_num) {
    if (typeof window.__cloneChangeTabs === 'function') {
        return window.__cloneChangeTabs(elem, tab_num);
    }
    var tabs_over = $(elem).parents('[role="tabs"]').eq(0);
    if (tab_num != '') {
        history.replaceState('', '', window.location.pathname + '?tab=' + tab_num);
    } else {
        history.replaceState('', '', window.location.pathname);
    }
    $(tabs_over).find('[tab]').removeClass('active');
    $(tabs_over).find('[tab=\"' + tab_num + '\"]').addClass('active');
    $(tabs_over).find('.change_view').removeClass('active');
    $(elem).addClass('active');
}
"""

paths = list((TPL / "components/bitrix/news").glob("**/news.detail/**/script.js"))
paths += list((TPL / "components/bitrix/news").glob("**/source/script.js"))
# also client_news already may have delegate
count = 0
for p in paths:
    if ".bak" in str(p):
        continue
    t = p.read_text(encoding="utf-8", errors="replace")
    if "function change_tabs" not in t:
        continue
    if "__cloneChangeTabs" in t and "function change_tabs" in t:
        # already delegates somehow
        m = re.search(r"function change_tabs\s*\([^)]*\)\s*\{", t)
        if m and "__cloneChangeTabs" in t[m.start() : m.start() + 250]:
            continue
    m = re.search(r"function change_tabs\s*\([^)]*\)\s*\{", t)
    if not m:
        continue
    i = m.end() - 1
    depth = 0
    end = None
    for j in range(i, len(t)):
        if t[j] == "{":
            depth += 1
        elif t[j] == "}":
            depth -= 1
            if depth == 0:
                end = j + 1
                break
    if not end:
        print("no end", p)
        continue
    t = t[: m.start()] + delegate + t[end:]
    p.write_text(t, encoding="utf-8")
    count += 1
    print("patched", p.relative_to(TPL))

print("patched count", count)

# Ensure client_news init still lazy + has opening markup
cn = TPL / "components/bitrix/news/client_news/bitrix/news.detail/.default/tabs/init.php"
t = cn.read_text(encoding="utf-8", errors="replace")
# strip any leftover huge inline if present
t2 = re.sub(r"<script>\s*/\* CLONE_TABS_[\s\S]*?</script>\s*", "", t)
t2 = re.sub(r"<script>\s*/\* Stable:[\s\S]*?</script>\s*", "", t2)
if "if ($tab_active == $arTab['tab'])" not in t2 and "CLONE SPEED" not in t2:
